query:
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '1.', 'Yaptığı işi en iyi şekilde yapar. İş disiplini ve görev bilinci yüksektir.' FROM position_categories WHERE positionId = 8 AND name = 'Görev Bilinci' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '2.', 'Sorumluluğundaki işleri, şirket kural ve prosedürlerine uygun bir biçimde gerçekleştirir.' FROM position_categories WHERE positionId = 8 AND name = 'Görev Bilinci' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '3.', 'İşine, kuruma ve kendisine sunulan kaynaklara zarar verecek hiçbir davranış sergilemez.' FROM position_categories WHERE positionId = 8 AND name = 'Görev Bilinci' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '4.', 'Ahlaki ve etik değerlere uygun davranır.' FROM position_categories WHERE positionId = 8 AND name = 'Görev Bilinci' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '5.', 'Karşındakini dinler ve verilmek istenen mesajı doğru bir şekilde anlar.' FROM position_categories WHERE positionId = 8 AND name = 'İletişim Becerisi' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '6.', 'Söylemek istediklerini, açık, kısa ve net bir biçimde karşı tarafa aktarır.' FROM position_categories WHERE positionId = 8 AND name = 'İletişim Becerisi' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '7.', 'İşle ilgili konularla ilgili bilgiyi zamanında aktarır ve paylaşır.' FROM position_categories WHERE positionId = 8 AND name = 'İletişim Becerisi' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '8.', 'Her türlü iletişimde empati kurmaya özen gösterir.' FROM position_categories WHERE positionId = 8 AND name = 'İletişim Becerisi' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '9.', 'Gelişmekte olan problemleri görür, önleyici davranış geliştirir.' FROM position_categories WHERE positionId = 8 AND name = 'Analitik Düşünme ve Problem Çözme' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '10.', 'Durum ve problem karşısında alacağı hareketin sonucunu bilir.' FROM position_categories WHERE positionId = 8 AND name = 'Analitik Düşünme ve Problem Çözme' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '11.', 'Mevcut sorunu gidermek için alternatif çözüm yolları geliştirir.' FROM position_categories WHERE positionId = 8 AND name = 'Analitik Düşünme ve Problem Çözme' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '12.', 'Benzer sorunlar arasında ilişki kurar; geçmişteki deneyimlerden faydalanır.' FROM position_categories WHERE positionId = 8 AND name = 'Analitik Düşünme ve Problem Çözme' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '13.', 'Mevcut düzen ve iş yapma yöntemine uygun çalışır.' FROM position_categories WHERE positionId = 8 AND name = 'Kalite Odaklılık' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '14.', 'Kaliteyi belirlenen standartlara göre uyarlar.' FROM position_categories WHERE positionId = 8 AND name = 'Kalite Odaklılık' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText) SELECT id, '15.', 'Yapılan işin kalitesini sürekli geliştirmek yönünde çalışır.' FROM position_categories WHERE positionId = 8 AND name = 'Kalite Odaklılık' LIMIT 1;

